<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue';
import { CURRENT_VERSION, manualCheckUpdates, performExtensionUpdate, reloadHostPage } from '../versionCheck';
import CatIcon from './CatIcon.vue';

const AUTH_API_URL = 'https://maomaomz-auth.baobaoyu999727272.workers.dev';

const currentVersion = CURRENT_VERSION;
const isCheckingUpdate = ref(false);
const isForceUpdating = ref(false);
const pluginUsage = ref('加载中...');
const pluginChangelog = ref('加载中...');

const expandedSections = reactive({
  usageGuide: true,
  changelog: true,
});

const toggleSection = (section: keyof typeof expandedSections) => {
  expandedSections[section] = !expandedSections[section];
};

const checkForUpdates = async () => {
  if (isCheckingUpdate.value) return;

  isCheckingUpdate.value = true;
  try {
    await manualCheckUpdates();
  } catch (error) {
    console.error('❌ 检查更新失败:', error);
  } finally {
    isCheckingUpdate.value = false;
  }
};

// 强制更新
const forceUpdate = async () => {
  if (isForceUpdating.value) return;

  isForceUpdating.value = true;

  try {
    const result = await performExtensionUpdate();
    if (result.success) {
      window.toastr?.success('✅ 更新成功！3秒后刷新页面...', '完成');
      setTimeout(() => reloadHostPage(), 3000);
    } else {
      window.toastr?.warning(
        `⚠️ 自动更新失败，请手动更新后刷新页面\n\n${result.error || '未知错误'}`,
        '请手动更新',
        { timeOut: 0, closeButton: true },
      );
    }
  } catch (error) {
    console.error('❌ 强制更新失败:', error);
    window.toastr?.error('❌ 更新失败，请查看控制台', '错误');
  } finally {
    isForceUpdating.value = false;
  }
};

// 从后端加载插件信息
const loadPluginInfo = async () => {
  try {
    console.log('🔍 正在从后端加载使用说明和更新日志...');
    const response = await fetch(`${AUTH_API_URL}/plugin-info`);
    const result = await response.json();

    if (result.success && result.data) {
      pluginUsage.value = result.data.usage || '暂无使用说明';
      pluginChangelog.value = result.data.changelog || '暂无更新日志';
      console.log('✅ 成功加载插件信息', result.data);
    } else {
      pluginUsage.value = '❌ 加载失败，请稍后重试';
      pluginChangelog.value = '❌ 加载失败，请稍后重试';
    }
  } catch (error) {
    console.error('❌ 加载插件信息失败:', error);
    pluginUsage.value = '❌ 无法连接到服务器';
    pluginChangelog.value = '❌ 无法连接到服务器';
  }
};

// 简单的 Markdown 渲染函数
const renderMarkdown = (text: string): string => {
  if (!text) return '';

  let html = text;

  // 转义 HTML 特殊字符（防止 XSS）
  html = html
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');

  // 引用块（> 开头的行）- 转义后变成 &gt;
  html = html.replace(/^&gt; (.+)$/gm, '<blockquote-line>$1</blockquote-line>');
  html = html.replace(/(<blockquote-line>[\s\S]+?<\/blockquote-line>\n?)+/g, match => {
    const content = match.replace(/<blockquote-line>/g, '').replace(/<\/blockquote-line>\n?/g, '<br>');
    return (
      '<blockquote style="border-left: 4px solid #4a9eff; background: rgba(74, 158, 255, 0.1); padding: 12px 16px; margin: 12px 0; border-radius: 4px; color: #e0e0e0;">' +
      content +
      '</blockquote>'
    );
  });

  // 标题（# ## ###）
  html = html.replace(/^### (.+)$/gm, '<h3 style="color: #4a9eff; margin: 15px 0 10px 0; font-size: 16px;">$1</h3>');
  html = html.replace(/^## (.+)$/gm, '<h2 style="color: #4a9eff; margin: 20px 0 12px 0; font-size: 18px;">$1</h2>');
  html = html.replace(
    /^# (.+)$/gm,
    '<h1 style="color: #4a9eff; margin: 20px 0 15px 0; font-size: 20px; font-weight: 600;">$1</h1>',
  );

  // 加粗 **text**
  html = html.replace(/\*\*(.+?)\*\*/g, '<strong style="color: #fff; font-weight: 600;">$1</strong>');

  // 斜体 *text*
  html = html.replace(/\*(.+?)\*/g, '<em style="color: #ccc; font-style: italic;">$1</em>');

  // 行内代码 `code`
  html = html.replace(
    /`([^`]+)`/g,
    '<code style="background: rgba(255, 255, 255, 0.1); padding: 2px 6px; border-radius: 4px; color: #4a9eff; font-family: monospace;">$1</code>',
  );

  // 无序列表 - item
  html = html.replace(/^- (.+)$/gm, '<li style="margin: 5px 0; padding-left: 8px;">$1</li>');
  html = html.replace(
    /(<li.*<\/li>\n?)+/g,
    '<ul style="margin: 10px 0; padding-left: 20px; list-style-type: disc;">$&</ul>',
  );

  // 有序列表 1. item
  html = html.replace(/^\d+\. (.+)$/gm, '<li style="margin: 5px 0; padding-left: 8px;">$1</li>');

  // 链接 [text](url)
  html = html.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2" target="_blank" style="color: #4a9eff; text-decoration: none; border-bottom: 1px solid #4a9eff;">$1</a>',
  );

  // 水平线 ---
  html = html.replace(
    /^---$/gm,
    '<hr style="border: none; border-top: 1px solid rgba(255, 255, 255, 0.1); margin: 20px 0;">',
  );

  // 换行（两个空格+换行 或 \n\n）
  html = html.replace(/\n\n/g, '<br><br>');
  html = html.replace(/ {2}\n/g, '<br>');

  return html;
};

// 页面加载时获取插件信息
onMounted(() => {
  loadPluginInfo();
});
</script>

